  const map = L.map('wedding-map', {
    scrollWheelZoom: false
  });

  L.tileLayer('https://{s}.tile.openstreetmap.org/{z}/{x}/{y}.png', {
    maxZoom: 12,
    minZoom: 6,
    attribution: ''
  }).addTo(map);

  /* HALVÁNY KÉK AURA – prémium, visszafogott glow */
  const auraLayer = L.geoJSON(isochroneData, {
    style: {
      color: 'rgba(168, 195, 232, 0.40)', /* halvány elegáns kék */
      weight: 12,
      fillOpacity: 0
    }
  }).addTo(map);

  /* ARANY KITÖLTÉS + ARANY KONTÚR – letisztult, finom */
  const mainLayer = L.geoJSON(isochroneData, {
    style: {
      color: 'rgba(201, 167, 105, 0.85)',       /* arany kontúr */
      weight: 1.4,
      fillColor: 'rgba(251, 237, 213, 0.60)',   /* nagyon halvány arany */
      fillOpacity: 0.55                         /* finom, elegáns */
    }
  }).addTo(map);

  /* TÉRKÉPET IGAZÍTJA A POLYGONHOZ */
  map.fitBounds(mainLayer.getBounds());
